using System.ComponentModel.DataAnnotations;
using System.Diagnostics.CodeAnalysis;

namespace Lumeo;

public class DataAnnotationsFormValidator : IFormValidator
{
    /// <summary>
    /// Sentinel key under which form-level (class-level) validation errors are
    /// recorded — i.e. results whose <see cref="ValidationResult.MemberNames"/> is
    /// empty (produced by <see cref="IValidatableObject"/> or a class-scoped
    /// validation attribute). A FormMessage with this Name surfaces them.
    /// </summary>
    public const string FormLevelErrorKey = "__form";

    [RequiresUnreferencedCode("DataAnnotations validation reflects over the model's runtime " +
        "type (ValidationContext resolves DisplayNameAttribute; Validator walks [Validation] " +
        "attributes on its members). Safe when the model's type preserves its public members.")]
    public Dictionary<string, List<string>> Validate(object model)
    {
        var results = new List<ValidationResult>();
        var context = new ValidationContext(model);
        Validator.TryValidateObject(model, context, results, true);

        var errors = new Dictionary<string, List<string>>();
        foreach (var result in results)
        {
            // Class-level / form-level validation (e.g. IValidatableObject or a
            // class-scoped attribute) yields an empty MemberNames. Without a
            // sentinel key those errors are silently dropped, so the form would
            // report valid while DataAnnotations actually failed. Record them
            // under FormLevelErrorKey so a form-level FormMessage can surface them.
            var memberNames = result.MemberNames.Any()
                ? result.MemberNames
                : new[] { FormLevelErrorKey };
            foreach (var memberName in memberNames)
            {
                if (!errors.ContainsKey(memberName))
                    errors[memberName] = new List<string>();
                if (result.ErrorMessage is not null)
                    errors[memberName].Add(result.ErrorMessage);
            }
        }
        return errors;
    }

    [RequiresUnreferencedCode("DataAnnotations validation reflects over the model's runtime " +
        "type (ValidationContext resolves DisplayNameAttribute; Type.GetProperty(fieldName) " +
        "looks up the target member). Safe when the model's type preserves its public members.")]
    public List<string> ValidateField(object model, string fieldName)
    {
        var results = new List<ValidationResult>();
        var context = new ValidationContext(model) { MemberName = fieldName };
        var prop = model.GetType().GetProperty(fieldName);
        if (prop is null) return new();
        Validator.TryValidateProperty(prop.GetValue(model), context, results);
        return results.Where(r => r.ErrorMessage is not null).Select(r => r.ErrorMessage!).ToList();
    }
}

@namespace Lumeo
@typeparam TModel
@using System.Text.Json.Serialization.Metadata

<CascadingValue Value="_context" IsFixed="false">
    <form @onsubmit="HandleSubmit" class="@(Cx.Merge("space-y-4", Class))" @attributes="AdditionalAttributes">
        @ChildContent
    </form>
</CascadingValue>

@code {
    /// <summary>The form's data model. A JSON snapshot is captured on init (and re-captured whenever a new instance is bound) so <see cref="ResetValues"/> can restore it later.</summary>
    [Parameter] public TModel? Model { get; set; }
    /// <summary>The form's fields — typically a sequence of <see cref="FormField"/>s wrapping bound inputs.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Invoked with <see cref="Model"/> on submit when validation passes (no <see cref="Validator"/>, or it reports no errors).</summary>
    [Parameter] public EventCallback<TModel> OnValidSubmit { get; set; }
    /// <summary>Invoked with <see cref="Model"/> on submit when <see cref="Validator"/> reports validation errors.</summary>
    [Parameter] public EventCallback<TModel> OnInvalidSubmit { get; set; }
    /// <summary>Optional synchronous validator run on submit and via <see cref="ValidateField"/>; its errors are merged into the cascaded <c>FormContext</c> alongside any async field-level errors.</summary>
    [Parameter] public IFormValidator? Validator { get; set; }
    /// <summary>Additional CSS classes merged onto the <c>&lt;form&gt;</c> element.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>
    /// Optional source-generated <see cref="JsonTypeInfo{T}"/> for <typeparamref name="TModel"/>,
    /// used for the init/<see cref="ResetValues"/> snapshot round-trip instead of reflection-based
    /// serialization. Without this, the snapshot uses <c>JsonSerializer.Serialize/Deserialize&lt;TModel&gt;</c>
    /// via reflection: <typeparamref name="TModel"/> itself carries <c>[DynamicallyAccessedMembers(All)]</c>
    /// so ITS members survive trimming, but that annotation does NOT cascade into the types of
    /// <typeparamref name="TModel"/>'s own reference-type properties (e.g. a nested <c>Address</c>
    /// POCO) — their members can still be trimmed away, silently dropping nested values on
    /// <see cref="ResetValues"/>. Pass your own <c>JsonSerializerContext</c>-generated
    /// <c>MyModelContext.Default.TModel</c> here to cover the whole object graph and be fully
    /// trim-safe (#364 review).
    /// </summary>
    [Parameter] public JsonTypeInfo<TModel>? ModelTypeInfo { get; set; }
    /// <summary>Unmatched attributes splatted onto the <c>&lt;form&gt;</c> element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private FormContext _context = new();
    // JSON snapshot of the Model captured at initialization. Used by ResetValues() to
    // restore the Model to its initial state. Captured via System.Text.Json round-trip
    // so it covers nested objects and record types without needing to know the schema.
    private string? _initialModelSnapshot;
    // The Model instance the snapshot was taken from. When the parent swaps in a
    // different Model instance, the snapshot must be re-captured against the new
    // baseline — otherwise ResetValues() would restore the PREVIOUS model's values
    // onto the current one. Tracked by reference so same-instance mutations (the
    // common edit-then-reset flow) keep the original baseline.
    private object? _snapshotModel;
    // The ModelTypeInfo the snapshot was captured WITH. A parent that supplies
    // ModelTypeInfo after the first render (or swaps it) while keeping the same Model
    // instance must still trigger a re-capture: the initial reflection-based snapshot
    // (ModelTypeInfo null) can silently miss nested members in a trimmed app, so once a
    // trim-safe context arrives it needs to replace that stale/incomplete snapshot
    // rather than be ignored because Model didn't change (#366 review).
    private JsonTypeInfo<TModel>? _snapshotModelTypeInfo;

    protected override Task OnInitializedAsync()
    {
        CaptureInitialSnapshot();
        return Task.CompletedTask;
    }

    protected override void OnParametersSet()
    {
        // Re-capture the reset baseline whenever the Model parameter is a different
        // instance than the one we snapshotted, OR ModelTypeInfo changed while Model
        // stayed the same (see _snapshotModelTypeInfo above). OnInitializedAsync already
        // captured the very first instance, so this only fires on subsequent changes.
        if (!ReferenceEquals(Model, _snapshotModel) || !ReferenceEquals(ModelTypeInfo, _snapshotModelTypeInfo))
        {
            CaptureInitialSnapshot();
        }
    }

    [System.Diagnostics.CodeAnalysis.UnconditionalSuppressMessage("Trimming", "IL2026",
        Justification = "Reflection fallback only (ModelTypeInfo is null): TModel carries " +
            "[DynamicallyAccessedMembers(All)] (see Form.razor.cs), which preserves TModel's OWN " +
            "members, so a flat model round-trips safely. It does NOT cover members of TModel's " +
            "nested reference-type properties — pass ModelTypeInfo for a full-graph trim guarantee.")]
    private void CaptureInitialSnapshot()
    {
        _snapshotModel = Model;
        _snapshotModelTypeInfo = ModelTypeInfo;

        if (Model is null)
        {
            _initialModelSnapshot = null;
            return;
        }

        try
        {
            _initialModelSnapshot = ModelTypeInfo is not null
                ? System.Text.Json.JsonSerializer.Serialize(Model, ModelTypeInfo)
                : System.Text.Json.JsonSerializer.Serialize(Model);
        }
        catch
        {
            // If the model is not JSON-serializable we silently skip the snapshot.
            // ResetValues() will then be a no-op (besides clearing errors).
            _initialModelSnapshot = null;
        }
    }

    // Error-list instances the sync Validator wrote, per field. Tracked so a
    // re-submit can drop errors for fields that now pass — Validate() only
    // returns failures, so merging alone left fixed fields permanently
    // invalid and OnValidSubmit could never fire again. Tracking the exact
    // INSTANCE (not just the key) keeps async-sourced errors safe even when
    // they reuse a key that sync once failed: an async validator overwriting
    // Errors[key] replaces the instance, so the cleanup below no longer
    // considers the entry sync-owned and leaves it alone (Codex P1 on the
    // earlier key-only tracking).
    private readonly Dictionary<string, List<string>> _syncWrittenErrors = new();

    [System.Diagnostics.CodeAnalysis.UnconditionalSuppressMessage("Trimming", "IL2026",
        Justification = "TModel carries [DynamicallyAccessedMembers(All)] (see Form.razor.cs), " +
            "so an IFormValidator implementation reflecting over Model is safe here.")]
    private async Task HandleSubmit()
    {
        if (Model is null) return;

        _context.IsSubmitting = true;
        StateHasChanged();

        try
        {
            if (Validator is not null)
            {
                // Merge sync validation results with any async errors already in the context
                // so per-field async validators (e.g. "username taken") survive a sync re-validate.
                var syncErrors = Validator.Validate(Model);
                foreach (var (key, written) in _syncWrittenErrors)
                {
                    if (!syncErrors.ContainsKey(key)
                        && _context.Errors.TryGetValue(key, out var current)
                        && ReferenceEquals(current, written))
                    {
                        _context.Errors.Remove(key);
                    }
                }
                foreach (var kvp in syncErrors)
                {
                    _context.Errors[kvp.Key] = kvp.Value;
                }
                _syncWrittenErrors.Clear();
                foreach (var kvp in syncErrors)
                {
                    _syncWrittenErrors[kvp.Key] = kvp.Value;
                }
            }

            if (_context.IsValid)
            {
                await OnValidSubmit.InvokeAsync(Model);
            }
            else
            {
                await OnInvalidSubmit.InvokeAsync(Model);
            }
        }
        finally
        {
            _context.IsSubmitting = false;
            StateHasChanged();
        }
    }

    [System.Diagnostics.CodeAnalysis.UnconditionalSuppressMessage("Trimming", "IL2026",
        Justification = "TModel carries [DynamicallyAccessedMembers(All)] (see Form.razor.cs), " +
            "so an IFormValidator implementation reflecting over Model is safe here.")]
    public void ValidateField(string fieldName)
    {
        if (Model is null || Validator is null) return;
        var errors = Validator.ValidateField(Model, fieldName);
        if (errors.Count > 0)
        {
            _context.Errors[fieldName] = errors;
            _syncWrittenErrors[fieldName] = errors;
        }
        else
        {
            // Only remove what sync validation owns — an async error that
            // replaced the instance under this key must survive.
            if (_syncWrittenErrors.TryGetValue(fieldName, out var written)
                && _context.Errors.TryGetValue(fieldName, out var current)
                && ReferenceEquals(current, written))
            {
                _context.Errors.Remove(fieldName);
            }
            _syncWrittenErrors.Remove(fieldName);
        }
        StateHasChanged();
    }

    public void Reset()
    {
        _syncWrittenErrors.Clear();
        _context.Reset();
        StateHasChanged();
    }

    /// <summary>
    /// Restores the <see cref="Model"/>'s public read/write properties to the values
    /// captured during <see cref="OnInitializedAsync"/>, and clears validation errors.
    /// <para>
    /// Implementation note: the snapshot is taken via a <c>System.Text.Json</c> round-trip,
    /// so the model type MUST be JSON-round-trippable — i.e. public properties with both a
    /// getter and a setter (or an init-only setter for record types), no recursive cycles,
    /// and serializable property types. Properties that are read-only, write-only, or marked
    /// <c>[JsonIgnore]</c> will NOT be restored. If the model failed to serialize at
    /// initialization time this method falls back to <see cref="Reset"/> behavior
    /// (errors cleared, values untouched).
    /// </para>
    /// <para>
    /// Trimming note: without <see cref="ModelTypeInfo"/>, the round-trip uses reflection and
    /// only <typeparamref name="TModel"/>'s OWN members are guaranteed to survive trimming —
    /// nested reference-type properties (e.g. <c>Model.Address.Street</c>) are not covered and
    /// may silently fail to restore in a trimmed app. Pass <see cref="ModelTypeInfo"/> for a
    /// full-graph trim guarantee.
    /// </para>
    /// </summary>
    [System.Diagnostics.CodeAnalysis.UnconditionalSuppressMessage("Trimming", "IL2026",
        Justification = "Reflection fallback only (ModelTypeInfo is null): TModel carries " +
            "[DynamicallyAccessedMembers(All)] (see Form.razor.cs), which preserves TModel's OWN " +
            "members, so a flat model round-trips safely. It does NOT cover members of TModel's " +
            "nested reference-type properties — pass ModelTypeInfo for a full-graph trim guarantee.")]
    public void ResetValues()
    {
        if (Model is not null && _initialModelSnapshot is not null)
        {
            try
            {
                var restored = ModelTypeInfo is not null
                    ? System.Text.Json.JsonSerializer.Deserialize(_initialModelSnapshot, ModelTypeInfo)
                    : System.Text.Json.JsonSerializer.Deserialize<TModel>(_initialModelSnapshot);
                if (restored is not null)
                {
                    CopyPublicProperties(restored, Model);
                }
            }
            catch
            {
                // Round-trip failed; leave Model untouched but still clear errors below.
            }
        }

        _syncWrittenErrors.Clear();
        _context.Reset();
        StateHasChanged();
    }

    // Copies public read/write properties from source to destination using reflection.
    // We mutate the existing Model instance (rather than reassigning the Model parameter)
    // because the parent component owns Model and reassigning a [Parameter] from inside
    // the child would be overwritten on the next render pass.
    private static void CopyPublicProperties(TModel source, TModel destination)
    {
        var type = typeof(TModel);
        foreach (var prop in type.GetProperties(System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance))
        {
            if (!prop.CanRead || !prop.CanWrite) continue;
            if (prop.GetIndexParameters().Length > 0) continue;
            try
            {
                var value = prop.GetValue(source);
                prop.SetValue(destination, value);
            }
            catch
            {
                // Skip properties whose setter throws (init-only on a non-record class, etc.).
            }
        }
    }
}

using System.Diagnostics.CodeAnalysis;

namespace Lumeo;

// Partial declaration carrying the trim annotation for the open TModel type parameter.
// Form.razor's generated partial declares `Form<TModel>` (no attribute); C# allows a
// generic type parameter's attributes/constraints to be declared on exactly one partial
// part, so this file is the sole place TModel's DynamicallyAccessedMembers lives.
//
// TModel is an arbitrary consumer POCO — Form serializes it via System.Text.Json (init
// snapshot + ResetValues round-trip) and reflects over its public properties
// (CopyPublicProperties). None of that is knowable at Lumeo-compile-time, so it can't be
// closed with a JsonSerializerContext; annotating TModel with [DynamicallyAccessedMembers(All)]
// instead makes the trimmer preserve every member of whatever concrete TModel a consumer
// instantiates Form<TModel> with (see #354).
public partial class Form<[DynamicallyAccessedMembers(DynamicallyAccessedMemberTypes.All)] TModel>
{
}

namespace Lumeo;

public class FormContext
{
    public Dictionary<string, List<string>> Errors { get; set; } = new();
    public HashSet<string> DirtyFields { get; set; } = new();
    public bool IsSubmitting { get; set; }
    public bool IsValid => Errors.Count == 0 || Errors.All(e => e.Value.Count == 0);

    // Tracks which fields currently have an in-flight async validation. The field
    // name (or a synthetic key when Name is unset) is added when validation starts
    // and removed when it completes or is cancelled.
    public HashSet<string> ValidatingFields { get; set; } = new();

    /// <summary>
    /// True when at least one FormField has an async validation in flight. Useful
    /// for disabling submit buttons while server-side checks are pending.
    /// </summary>
    public bool IsAnyFieldValidating => ValidatingFields.Count > 0;

    public List<string> GetFieldErrors(string fieldName) =>
        Errors.TryGetValue(fieldName, out var errors) ? errors : new();

    public bool HasError(string fieldName) => GetFieldErrors(fieldName).Count > 0;
    public bool IsDirty(string fieldName) => DirtyFields.Contains(fieldName);
    public bool IsFieldValidating(string fieldName) => ValidatingFields.Contains(fieldName);

    public void MarkDirty(string fieldName) => DirtyFields.Add(fieldName);

    public void MarkValidating(string fieldName, bool validating)
    {
        if (validating) ValidatingFields.Add(fieldName);
        else ValidatingFields.Remove(fieldName);
    }

    public void SetFieldError(string fieldName, string? error)
    {
        if (string.IsNullOrEmpty(error))
            Errors.Remove(fieldName);
        else
            Errors[fieldName] = new List<string> { error };
    }

    public void ClearErrors() => Errors.Clear();
    public void ClearFieldErrors(string fieldName) => Errors.Remove(fieldName);

    public void Reset()
    {
        Errors.Clear();
        DirtyFields.Clear();
        ValidatingFields.Clear();
        IsSubmitting = false;
    }
}

@namespace Lumeo

<p class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</p>

@code {
    /// <summary>Helper text describing the field, rendered below its label.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Additional CSS classes merged onto the <c>&lt;p&gt;</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the <c>&lt;p&gt;</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("text-[0.8rem] text-muted-foreground", Class);
}

@namespace Lumeo
@using Lumeo.Internal
@implements IDisposable

@{
    var context = new FormFieldContext(Name, EffectiveError, IsValidating, _controlId, DescribedBy, AutoRenderMessage, _errorId, Label is not null ? _labelId : null);
}

<CascadingValue Value="context" IsFixed="false">
    <div class="@CssClass" @attributes="AdditionalAttributes">
        @if (Orientation == Lumeo.Orientation.Vertical)
        {
            @if (Label is not null)
            {
                <Label For="@_controlId" id="@_labelId">
                    <span class="inline-flex items-center gap-1.5">
                        @Label
                        @if (Required)
                        {
                            <span class="text-destructive ms-0.5">*</span>
                        }
                        @if (IsValidating)
                        {
                            <Spinner Size="Lumeo.Size.Sm" Color="text-muted-foreground" />
                        }
                    </span>
                </Label>
            }
            @ChildContent
            @if (HelpText is not null && EffectiveError is null)
            {
                <p id="@_descriptionId" class="text-xs text-muted-foreground">@HelpText</p>
            }
            @if (EffectiveError is not null && AutoRenderMessage)
            {
                <p id="@_errorId" class="text-xs text-destructive" role="alert" aria-live="polite">@EffectiveError</p>
            }
        }
        else
        {
            <div class="grid grid-cols-[auto_1fr] items-center gap-x-4 gap-y-1">
                @if (Label is not null)
                {
                    <Label For="@_controlId" id="@_labelId" Class="@(Cx.Join("text-end", LabelWidth is not null ? $"w-[{LabelWidth}]" : null))">
                        <span class="inline-flex items-center justify-end gap-1.5">
                            @Label
                            @if (Required)
                            {
                                <span class="text-destructive ms-0.5">*</span>
                            }
                            @if (IsValidating)
                            {
                                <Spinner Size="Lumeo.Size.Sm" Color="text-muted-foreground" />
                            }
                        </span>
                    </Label>
                }
                <div>
                    @ChildContent
                    @if (HelpText is not null && EffectiveError is null)
                    {
                        <p id="@_descriptionId" class="text-xs text-muted-foreground mt-1">@HelpText</p>
                    }
                    @if (EffectiveError is not null && AutoRenderMessage)
                    {
                        <p id="@_errorId" class="text-xs text-destructive mt-1" role="alert" aria-live="polite">@EffectiveError</p>
                    }
                </div>
            </div>
        }
    </div>
</CascadingValue>

@code {
    /// <summary>Label text rendered above (or, in <see cref="Lumeo.Orientation.Horizontal"/> mode, beside) the control, linked via <c>&lt;label for&gt;</c> to <see cref="ChildContent"/>'s bound input.</summary>
    [Parameter] public string? Label { get; set; }
    /// <summary>Helper text shown below the control when there is no active error.</summary>
    [Parameter] public string? HelpText { get; set; }
    /// <summary>Manually-set error message, used when there's no parent <c>Form</c> context (or no <see cref="Name"/>) to source live errors from. A live error from the form's validation always takes precedence.</summary>
    [Parameter] public string? Error { get; set; }
    /// <summary>Marks the field as required, rendering a visual asterisk next to <see cref="Label"/>.</summary>
    [Parameter] public bool Required { get; set; }
    /// <summary>Layout direction: <c>Vertical</c> (default) stacks label above the control; <c>Horizontal</c> places a right-aligned label beside it in a two-column grid.</summary>
    [Parameter] public Lumeo.Orientation Orientation { get; set; } = Lumeo.Orientation.Vertical;

    /// <summary>
    /// When <c>true</c> (default — the simple-mode API used by the vast majority of
    /// consumers), FormField renders the validation error itself below the control.
    /// Set <c>false</c> when you compose the field with a child <see cref="FormMessage"/>
    /// that should own the error rendering: this suppresses FormField's own error so the
    /// two never render it twice. The error still flows into the cascaded context either
    /// way, so a deferred FormMessage can pick it up.
    /// </summary>
    [Parameter] public bool AutoRenderMessage { get; set; } = true;
    /// <summary>Fixed CSS width for the label column in <see cref="Lumeo.Orientation.Horizontal"/> mode (e.g. <c>"8rem"</c>). Ignored in <c>Vertical</c> mode.</summary>
    [Parameter] public string? LabelWidth { get; set; }
    /// <summary>Field key used to look up live validation errors from the parent <c>Form</c>'s context, and as the async-validation registration key.</summary>
    [Parameter] public string? Name { get; set; }
    /// <summary>The bound input control(s) this field wraps.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Additional CSS classes merged onto the field's root element.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the field's root element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // --- Async validation ---
    /// <summary>
    /// Optional async validator. Receives the current <see cref="Value"/>, returns
    /// null when valid or an error message string otherwise. The result is stored
    /// in <see cref="FormContext.Errors"/> against <see cref="Name"/>.
    /// </summary>
    [Parameter] public Func<object?, Task<string?>>? AsyncValidator { get; set; }

    /// <summary>Debounce window in ms. 0 disables debouncing.</summary>
    [Parameter] public int AsyncValidationDebounceMs { get; set; } = 0;

    /// <summary>When async validation runs. Defaults to <see cref="AsyncValidationTrigger.OnBlur"/>.</summary>
    [Parameter] public AsyncValidationTrigger AsyncValidateOn { get; set; } = AsyncValidationTrigger.OnBlur;

    /// <summary>
    /// Current value of the bound input. Required for <see cref="AsyncValidationTrigger.OnChange"/>
    /// auto-triggering; also passed to the validator on blur. If unset, consumers may invoke
    /// <see cref="ValidateAsync(object?)"/> directly.
    /// </summary>
    [Parameter] public object? Value { get; set; }

    /// <summary>Fired whenever <see cref="IsValidating"/> flips.</summary>
    [Parameter] public EventCallback<bool> OnValidatingChanged { get; set; }

    public bool IsValidating { get; private set; }

    // Bug D fix: receive the parent Form's context so Reset() clears cascade to child fields.
    [CascadingParameter] private FormContext? ParentFormContext { get; set; }

    // Stable ids so the field's label points at the control and the control's
    // aria-describedby points at the help/error text (Base UI Field a11y parity).
    private readonly string _controlId = LumeoIds.New("form-field");
    private readonly string _descriptionId = LumeoIds.New("form-field-desc");
    private readonly string _errorId = LumeoIds.New("form-field-error");
    // Stable id on the <Label> itself, exposed via FormFieldContext.LabelId, for controls whose root
    // is NOT a "labelable" element (a <div role="group">, e.g. TimeWheelPicker/Calendar) — `<label for>`
    // does not reliably associate with those, so they additionally wire `aria-labelledby` to this id
    // (Codex P2). Only set in the context when Label is actually rendered (else it would be a dangling
    // IDREF with nothing in the DOM to point at).
    private readonly string _labelId = LumeoIds.New("form-field-label");

    // Point aria-describedby at whichever message is actually rendered: the error
    // when present (it replaces the help text), else the help text, else nothing.
    private string? DescribedBy => EffectiveError is not null
        ? _errorId
        : (HelpText is not null ? _descriptionId : null);

    // Use live errors from FormContext when available; fall back to the manually-set Error param.
    private string? EffectiveError =>
        ParentFormContext is { } pc && !string.IsNullOrEmpty(Name)
            ? pc.GetFieldErrors(Name).FirstOrDefault() ?? Error
            : Error;

    private string CssClass => Orientation == Lumeo.Orientation.Vertical
        ? Cx.Merge("space-y-2", Class)
        : Cx.Merge(Class);

    // Async machinery
    private DebouncedValue<object?>? _debouncer;
    private int _lastDebounceMs = -1;
    private CancellationTokenSource? _cts;
    private object? _previousValue;
    private bool _hasPreviousValue;
    // Synthetic key used when no Name is set so the validating-fields set still aggregates.
    private string FieldKey => string.IsNullOrEmpty(Name) ? $"__field_{GetHashCode()}" : Name!;
    // The key this field was last registered under as "validating". Captured when
    // validation starts so the matching un-register targets the SAME key even if the
    // Name parameter changes mid-flight — otherwise the old key leaks in
    // FormContext.ValidatingFields and IsAnyFieldValidating stays stuck true.
    private string? _validatingKey;

    protected override async Task OnParametersSetAsync()
    {
        // Re-create the debouncer if the window changed.
        if (_lastDebounceMs != AsyncValidationDebounceMs)
        {
            _debouncer?.Dispose();
            _debouncer = AsyncValidationDebounceMs > 0
                ? new DebouncedValue<object?>(AsyncValidationDebounceMs)
                : null;
            _debouncer?.OnChanged(RunValidationAsync);
            _lastDebounceMs = AsyncValidationDebounceMs;
        }

        // Detect value changes for OnChange trigger. Skip the first parameter-set
        // pass so we don't auto-validate before the user has interacted.
        //
        // Use a CONTENT-aware comparison rather than the static object.Equals:
        // when the parent re-renders and pushes a NEW reference that is value-equal
        // to the previous one (e.g. a freshly-allocated but same-content collection
        // produced by an immutable update, or a record), that must NOT count as a
        // change. The static object.Equals path falls back to reference equality for
        // any reference type that doesn't override Equals (sequences in particular),
        // so an identical-content re-render spuriously re-fired async validation on
        // every unrelated parent render — kicking off a network call the user never
        // asked for and flickering IsValidating.
        if (AsyncValidator is not null && AsyncValidateOn == AsyncValidationTrigger.OnChange)
        {
            if (_hasPreviousValue && !ValueContentEquals(_previousValue, Value))
            {
                ScheduleValidation(Value);
            }
        }
        _previousValue = Value;
        _hasPreviousValue = true;

        await Task.CompletedTask;
    }

    /// <summary>
    /// Content-aware equality for the OnChange trigger. Treats two distinct
    /// references as equal when they carry the same content, so an immutable
    /// "rebuild a new equal collection each render" parent (or a value-equal
    /// record) does not look like a user edit. Falls back to <see cref="object.Equals(object?, object?)"/>
    /// for everything that already has value semantics.
    /// </summary>
    private static bool ValueContentEquals(object? a, object? b)
    {
        if (ReferenceEquals(a, b)) return true;
        if (a is null || b is null) return false;
        // Same-content sequence (List/array/etc.) rebuilt across renders: a brand-new
        // reference that object.Equals would wrongly report as different. Only when both
        // sides are non-string enumerables (strings are themselves IEnumerable<char> but
        // already have value equality, so let them fall through to Equals).
        if (a is System.Collections.IEnumerable ea and not string &&
            b is System.Collections.IEnumerable eb and not string)
        {
            return SequenceContentEquals(ea, eb);
        }
        return Equals(a, b);
    }

    private static bool SequenceContentEquals(System.Collections.IEnumerable a, System.Collections.IEnumerable b)
    {
        var ia = a.GetEnumerator();
        var ib = b.GetEnumerator();
        try
        {
            while (true)
            {
                var ha = ia.MoveNext();
                var hb = ib.MoveNext();
                if (ha != hb) return false;      // different lengths
                if (!ha) return true;            // both exhausted, all equal
                if (!Equals(ia.Current, ib.Current)) return false;
            }
        }
        finally
        {
            (ia as IDisposable)?.Dispose();
            (ib as IDisposable)?.Dispose();
        }
    }

    /// <summary>
    /// Manually trigger async validation (e.g. wire to an input's @onblur). Honors
    /// the configured debounce window. Passes <paramref name="value"/> to the validator;
    /// if null the current <see cref="Value"/> parameter is used.
    /// </summary>
    public Task ValidateAsync(object? value = null)
    {
        if (AsyncValidator is null) return Task.CompletedTask;
        ScheduleValidation(value ?? Value);
        return Task.CompletedTask;
    }

    private void ScheduleValidation(object? value)
    {
        if (AsyncValidator is null) return;
        if (_debouncer is not null)
        {
            _debouncer.Set(value);
        }
        else
        {
            _ = RunValidationAsync(value);
        }
    }

    private async Task RunValidationAsync(object? value)
    {
        var validator = AsyncValidator;
        if (validator is null) return;

        // Cancel previous in-flight call.
        _cts?.Cancel();
        _cts?.Dispose();
        var cts = new CancellationTokenSource();
        _cts = cts;
        var token = cts.Token;

        await SetValidatingAsync(true);

        string? error = null;
        try
        {
            error = await validator(value).ConfigureAwait(true);
        }
        catch (OperationCanceledException)
        {
            return;
        }
        catch
        {
            // Swallow to avoid breaking the form; surface no error rather than throwing.
        }

        if (token.IsCancellationRequested) return;

        if (ParentFormContext is { } ctx && !string.IsNullOrEmpty(Name))
        {
            ctx.SetFieldError(Name!, error);
        }
        else
        {
            // No parent context / no Name: fall back to the local Error parameter via re-render.
            Error = error;
        }

        await SetValidatingAsync(false);
        StateHasChanged();
    }

    private async Task SetValidatingAsync(bool validating)
    {
        if (IsValidating == validating) return;
        IsValidating = validating;
        if (ParentFormContext is not null)
        {
            // Register under the CURRENT key, but un-register under the key we
            // registered with. If Name changed while validation was in flight,
            // FieldKey now differs and a naive un-register would leak the old key.
            if (validating)
            {
                _validatingKey = FieldKey;
                ParentFormContext.MarkValidating(_validatingKey, true);
            }
            else
            {
                ParentFormContext.MarkValidating(_validatingKey ?? FieldKey, false);
                _validatingKey = null;
            }
        }
        if (OnValidatingChanged.HasDelegate)
        {
            await OnValidatingChanged.InvokeAsync(validating);
        }
        StateHasChanged();
    }

    public void Dispose()
    {
        _debouncer?.Dispose();
        _cts?.Cancel();
        _cts?.Dispose();
        if (ParentFormContext is not null)
        {
            // Clear under the key we actually registered with (which may differ from
            // the current FieldKey if Name changed mid-flight), so no stale entry is
            // left behind in FormContext.ValidatingFields.
            ParentFormContext.MarkValidating(_validatingKey ?? FieldKey, false);
            _validatingKey = null;
        }
    }

    public enum AsyncValidationTrigger
    {
        OnBlur,
        OnChange
    }

    /// <param name="ControlId">Stable id the bound control should apply as its
    ///   <c>id</c> so the field's <c>&lt;label for&gt;</c> points at it (Base UI Field
    ///   parity). Empty when the field generated none.</param>
    /// <param name="DescribedBy">Id of the currently-rendered help OR error text, for
    ///   the control's <c>aria-describedby</c>; null when neither is shown.</param>
    /// <param name="LabelId">Id of the rendered &lt;label&gt; element, for controls whose root is NOT
    ///   labelable (a &lt;div role="group"&gt;) to wire as their own <c>aria-labelledby</c> — `label for`
    ///   alone doesn't reliably associate with a non-labelable element. Null when no Label is rendered.</param>
    public record FormFieldContext(string? Name, string? Error, bool IsValidating, string ControlId = "", string? DescribedBy = null, bool AutoRenderMessage = true, string? ErrorId = null, string? LabelId = null)
    {
        public bool HasError => !string.IsNullOrEmpty(Error);
    }
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    /// <summary>The item's content — typically a label, control, and description/message grouped as one field unit.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Additional CSS classes merged onto the root element.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the root element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("space-y-1", Class);
}

@namespace Lumeo

<label class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</label>

@code {
    [CascadingParameter] public FormField.FormFieldContext? FieldContext { get; set; }
    /// <summary>The label's text content.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Additional CSS classes merged onto the <c>&lt;label&gt;</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the <c>&lt;label&gt;</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(
        "text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70",
        Cx.When(FieldContext?.HasError == true, "text-destructive"),
        Class);
}

@namespace Lumeo

@* Render the error ONLY when the parent FormField is not auto-rendering it itself
   (i.e. FormField AutoRenderMessage="false"). By default FormField owns the error, so a
   stray <FormMessage/> stays silent instead of rendering the message a second time. *@
@if (FieldContext is { HasError: true, AutoRenderMessage: false })
{
    <p id="@FieldContext!.ErrorId" class="@CssClass" role="alert" aria-live="polite" @attributes="AdditionalAttributes">
        @FieldContext.Error
    </p>
}

@code {
    [CascadingParameter] public FormField.FormFieldContext? FieldContext { get; set; }
    /// <summary>Additional CSS classes merged onto the rendered error <c>&lt;p&gt;</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the rendered error <c>&lt;p&gt;</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("text-[0.8rem] font-medium text-destructive", Class);
}

using System.Diagnostics.CodeAnalysis;

namespace Lumeo;

public interface IFormValidator
{
    // model's actual type is only known at the call site (Form<TModel>'s Model), so an
    // implementation is free to use reflection (e.g. DataAnnotationsFormValidator does).
    // RequiresUnreferencedCode documents that honestly instead of silently swallowing an
    // ILLink warning here; see DataAnnotationsFormValidator and Form.razor's call sites
    // (both are trim-safe because TModel carries [DynamicallyAccessedMembers(All)]).
    [RequiresUnreferencedCode("Implementations may reflect over the model's runtime type " +
        "(e.g. DataAnnotationsFormValidator). Safe when the model's type preserves its " +
        "public members, as Form<TModel> guarantees via [DynamicallyAccessedMembers(All)] on TModel.")]
    Dictionary<string, List<string>> Validate(object model);

    [RequiresUnreferencedCode("Implementations may reflect over the model's runtime type " +
        "(e.g. DataAnnotationsFormValidator). Safe when the model's type preserves its " +
        "public members, as Form<TModel> guarantees via [DynamicallyAccessedMembers(All)] on TModel.")]
    List<string> ValidateField(object model, string fieldName);
}
